   1→/**
   2→ * LLM Proxy Acceptance Test Kit
   3→ *
   4→ * Domain-specific helpers for LLM proxy acceptance tests.
   5→ * Extends the shared acceptance-test-kit with proxy-specific
   6→ * workspace setup, request builders, and graph query helpers.
   7→ *
   8→ * Driving ports: HTTP endpoints at /proxy/llm/anthropic/v1/messages
   9→ * and /api/workspaces/:workspaceId/proxy/spend
  10→ */
  11→import { RecordId, type Surreal } from "surrealdb";
  12→import {
  13→  setupAcceptanceSuite,
  14→  createTestUser,
  15→  fetchRaw,
  16→  type AcceptanceTestRuntime,
  17→  type TestUser,
  18→} from "../acceptance-test-kit";
  19→
  20→// Re-export shared helpers
  21→export {
  22→  setupAcceptanceSuite,
  23→  createTestUser,
  24→  fetchRaw,
  25→  type AcceptanceTestRuntime,
  26→  type TestUser,
  27→};
  28→
  29→// ---------------------------------------------------------------------------
  30→// Proxy Request Builders
  31→// ---------------------------------------------------------------------------
  32→
  33→export type ProxyRequestOptions = {
  34→  model: string;
  35→  stream?: boolean;
  36→  maxTokens?: number;
  37→  messages?: Array<{ role: string; content: string }>;
  38→  metadata?: { user_id?: string };
  39→  apiKey?: string;
  40→  workspaceHeader?: string;
  41→  taskHeader?: string;
  42→  agentTypeHeader?: string;
  43→};
  44→
  45→/**
  46→ * Build a proxy request body matching the Anthropic Messages API format.
  47→ */
  48→export function buildProxyRequestBody(options: ProxyRequestOptions): string {
  49→  return JSON.stringify({
  50→    model: options.model,
  51→    max_tokens: options.maxTokens ?? 100,
  52→    stream: options.stream ?? false,
  53→    messages: options.messages ?? [
  54→      { role: "user", content: "Say hello in one word." },
  55→    ],
  56→    ...(options.metadata ? { metadata: options.metadata } : {}),
  57→  });
  58→}
  59→
  60→/**
  61→ * Build headers for a proxy request, including identity headers.
  62→ */
  63→export function buildProxyHeaders(options: ProxyRequestOptions): Record<string, string> {
  64→  const headers: Record<string, string> = {
  65→    "Content-Type": "application/json",
  66→    "anthropic-version": "2023-06-01",
  67→  };
  68→
  69→  if (options.apiKey) {
  70→    headers["x-api-key"] = options.apiKey;
  71→  }
  72→  if (options.workspaceHeader) {
  73→    headers["X-Brain-Workspace"] = options.workspaceHeader;
  74→  }
  75→  if (options.taskHeader) {
  76→    headers["X-Brain-Task"] = options.taskHeader;
  77→  }
  78→  if (options.agentTypeHeader) {
  79→    headers["X-Brain-Agent-Type"] = options.agentTypeHeader;
  80→  }
  81→
  82→  return headers;
  83→}
  84→
  85→/**
  86→ * Send a request through the LLM proxy endpoint.
  87→ * Returns the raw Response for flexible assertion.
  88→ */
  89→export async function sendProxyRequest(
  90→  baseUrl: string,
  91→  options: ProxyRequestOptions,
  92→): Promise<Response> {
  93→  const body = buildProxyRequestBody(options);
  94→  const headers = buildProxyHeaders(options);
  95→
  96→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
  97→    method: "POST",
  98→    headers,
  99→    body,
 100→  });
 101→}
 102→
 103→/**
 104→ * Send a count_tokens request through the proxy.
 105→ */
 106→export async function sendCountTokensRequest(
 107→  baseUrl: string,
 108→  options: ProxyRequestOptions,
 109→): Promise<Response> {
 110→  const body = buildProxyRequestBody(options);
 111→  const headers = buildProxyHeaders(options);
 112→
 113→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages/count_tokens`, {
 114→    method: "POST",
 115→    headers,
 116→    body,
 117→  });
 118→}
 119→
 120→// ---------------------------------------------------------------------------
 121→// SSE Stream Helpers
 122→// ---------------------------------------------------------------------------
 123→
 124→export type SSEEvent = {
 125→  event?: string;
 126→  data: string;
 127→};
 128→
 129→/**
 130→ * Collect all SSE events from a streaming proxy response.
 131→ */
 132→export async function collectProxySSEEvents(response: Response): Promise<SSEEvent[]> {
 133→  if (!response.body) {
 134→    throw new Error("No response body for SSE collection");
 135→  }
 136→
 137→  const reader = response.body.getReader();
 138→  const decoder = new TextDecoder();
 139→  const events: SSEEvent[] = [];
 140→  let buffer = "";
 141→
 142→  try {
 143→    while (true) {
 144→      const { done, value } = await reader.read();
 145→      if (done) break;
 146→
 147→      buffer += decoder.decode(value, { stream: true });
 148→      const segments = buffer.split("\n\n");
 149→      buffer = segments.pop() ?? "";
 150→
 151→      for (const segment of segments) {
 152→        const lines = segment.split("\n");
 153→        let eventType: string | undefined;
 154→        let dataLine: string | undefined;
 155→
 156→        for (const line of lines) {
 157→          if (line.startsWith("event: ")) {
 158→            eventType = line.slice(7);
 159→          } else if (line.startsWith("data: ")) {
 160→            dataLine = line.slice(6);
 161→          }
 162→        }
 163→
 164→        if (dataLine !== undefined) {
 165→          events.push({ event: eventType, data: dataLine });
 166→        }
 167→      }
 168→    }
 169→  } finally {
 170→    reader.releaseLock();
 171→  }
 172→
 173→  return events;
 174→}
 175→
 176→// ---------------------------------------------------------------------------
 177→// Workspace and Identity Setup
 178→// ---------------------------------------------------------------------------
 179→
 180→/**
 181→ * Create a workspace record in SurrealDB for proxy testing.
 182→ */
 183→export async function createProxyTestWorkspace(
 184→  surreal: Surreal,
 185→  workspaceId: string,
 186→  options?: { dailyBudget?: number; alertThreshold?: number },
 187→): Promise<string> {
 188→  const workspaceRecord = new RecordId("workspace", workspaceId);
 189→
 190→  const content: Record<string, unknown> = {
 191→    name: `Proxy Test Workspace ${workspaceId}`,
 192→    status: "active",
 193→    onboarding_complete: true,
 194→    onboarding_turn_count: 0,
 195→    onboarding_summary_pending: false,
 196→    onboarding_started_at: new Date(),
 197→    created_at: new Date(),
 198→  };
 199→
 200→  if (options?.dailyBudget !== undefined) {
 201→    content.daily_budget_usd = options.dailyBudget;
 202→  }
 203→
 204→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
 205→    workspace: workspaceRecord,
 206→    content,
 207→  });
 208→
 209→  return workspaceId;
 210→}
 211→
 212→/**
 213→ * Create a project record linked to a workspace.
 214→ */
 215→export async function createProxyTestProject(
 216→  surreal: Surreal,
 217→  projectId: string,
 218→  workspaceId: string,
 219→): Promise<string> {
 220→  const projectRecord = new RecordId("project", projectId);
 221→  const workspaceRecord = new RecordId("workspace", workspaceId);
 222→
 223→  await surreal.query(`CREATE $project CONTENT $content;`, {
 224→    project: projectRecord,
 225→    content: {
 226→      name: `Test Project ${projectId}`,
 227→      status: "active",
 228→      workspace: workspaceRecord,
 229→      created_at: new Date(),
 230→    },
 231→  });
 232→
 233→  return projectId;
 234→}
 235→
 236→/**
 237→ * Create a task record linked to a project and workspace.
 238→ */
 239→export async function createProxyTestTask(
 240→  surreal: Surreal,
 241→  taskId: string,
 242→  projectId: string,
 243→  workspaceId: string,
 244→): Promise<string> {
 245→  const taskRecord = new RecordId("task", taskId);
 246→  const projectRecord = new RecordId("project", projectId);
 247→  const workspaceRecord = new RecordId("workspace", workspaceId);
 248→
 249→  await surreal.query(`CREATE $task CONTENT $content;`, {
 250→    task: taskRecord,
 251→    content: {
 252→      title: `Test Task ${taskId}`,
 253→      status: "open",
 254→      workspace: workspaceRecord,
 255→      created_at: new Date(),
 256→    },
 257→  });
 258→
 259→  // Link task to project
 260→  await surreal.query(`RELATE $task->belongs_to->$project SET added_at = time::now();`, {
 261→    task: taskRecord,
 262→    project: projectRecord,
 263→  });
 264→
 265→  return taskId;
 266→}
 267→
 268→// ---------------------------------------------------------------------------
 269→// Graph Query Helpers
 270→// ---------------------------------------------------------------------------
 271→
 272→export type LlmTraceRecord = {
 273→  id: RecordId;
 274→  model: string;
 275→  input_tokens: number;
 276→  output_tokens: number;
 277→  cache_creation_tokens?: number;
 278→  cache_read_tokens?: number;
 279→  cost_usd: number;
 280→  latency_ms: number;
 281→  stop_reason?: string;
 282→  request_id?: string;
 283→  created_at: Date;
 284→};
 285→
 286→/**
 287→ * Query all LLM traces in a workspace.
 288→ */
 289→export async function getTracesForWorkspace(
 290→  surreal: Surreal,
 291→  workspaceId: string,
 292→): Promise<LlmTraceRecord[]> {
 293→  const workspaceRecord = new RecordId("workspace", workspaceId);
 294→
 295→  const results = await surreal.query(
 296→    `SELECT * FROM trace WHERE ->scoped_to->workspace CONTAINS $ws ORDER BY created_at DESC;`,
 297→    { ws: workspaceRecord },
 298→  );
 299→
 300→  return (results[0] ?? []) as LlmTraceRecord[];
 301→}
 302→
 303→/**
 304→ * Query traces attributed to a specific task.
 305→ */
 306→export async function getTracesForTask(
 307→  surreal: Surreal,
 308→  taskId: string,
 309→): Promise<LlmTraceRecord[]> {
 310→  const taskRecord = new RecordId("task", taskId);
 311→
 312→  const results = await surreal.query(
 313→    `SELECT * FROM trace WHERE ->attributed_to->task CONTAINS $task ORDER BY created_at DESC;`,
 314→    { task: taskRecord },
 315→  );
 316→
 317→  return (results[0] ?? []) as LlmTraceRecord[];
 318→}
 319→
 320→/**
 321→ * Check whether a trace has the expected graph edges.
 322→ */
 323→export async function getTraceEdges(
 324→  surreal: Surreal,
 325→  traceId: string,
 326→): Promise<{
 327→  workspaces: RecordId[];
 328→  tasks: RecordId[];
 329→  sessions: RecordId[];
 330→}> {
 331→  const traceRecord = new RecordId("trace", traceId);
 332→
 333→  const results = await surreal.query(
 334→    `SELECT
 335→       ->scoped_to->workspace AS workspaces,
 336→       ->attributed_to->task AS tasks,
 337→       <-invoked<-agent_session AS sessions
 338→     FROM $trace;`,
 339→    { trace: traceRecord },
 340→  );
 341→
 342→  const row = (results[0] as Array<{
 343→    workspaces: RecordId[];
 344→    tasks: RecordId[];
 345→    sessions: RecordId[];
 346→  }>)?.[0];
 347→
 348→  return {
 349→    workspaces: row?.workspaces ?? [],
 350→    tasks: row?.tasks ?? [],
 351→    sessions: row?.sessions ?? [],
 352→  };
 353→}
 354→
 355→/**
 356→ * Query the total spend for a workspace (sum of trace costs).
 357→ */
 358→export async function getWorkspaceSpend(
 359→  surreal: Surreal,
 360→  workspaceId: string,
 361→): Promise<number> {
 362→  const workspaceRecord = new RecordId("workspace", workspaceId);
 363→
 364→  const results = await surreal.query(
 365→    `SELECT cost_usd FROM trace WHERE workspace = $ws;`,
 366→    { ws: workspaceRecord },
 367→  );
 368→
 369→  const rows = (results[0] ?? []) as Array<{ cost_usd: number }>;
 370→  return rows.reduce((sum, row) => sum + (row.cost_usd ?? 0), 0);
 371→}
 372→
 373→/**
 374→ * Seed an LLM trace directly for testing dashboard/audit scenarios
 375→ * that need pre-existing trace data.
 376→ */
 377→export async function seedLlmTrace(
 378→  surreal: Surreal,
 379→  traceId: string,
 380→  options: {
 381→    model: string;
 382→    input_tokens: number;
 383→    output_tokens: number;
 384→    cost_usd: number;
 385→    latency_ms: number;
 386→    workspaceId: string;
 387→    taskId?: string;
 388→    sessionId?: string;
 389→    stop_reason?: string;
 390→    cache_read_tokens?: number;
 391→    cache_creation_tokens?: number;
 392→    created_at?: Date;
 393→  },
 394→): Promise<string> {
 395→  const traceRecord = new RecordId("trace", traceId);
 396→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 397→
 398→  // Ensure a test identity exists for the actor field (required by trace schema)
 399→  const actorId = `proxy-test-actor-${options.workspaceId}`;
 400→  const actorRecord = new RecordId("identity", actorId);
 401→  await surreal.query(
 402→    `CREATE $actor CONTENT { name: "proxy-test-system", type: "system", workspace: $ws, created_at: time::now() };`,
 403→    { actor: actorRecord, ws: workspaceRecord },
 404→  ).catch(() => undefined); // Ignore if already exists
 405→
 406→  const traceContent: Record<string, unknown> = {
 407→    type: "llm_call",
 408→    model: options.model,
 409→    input_tokens: options.input_tokens,
 410→    output_tokens: options.output_tokens,
 411→    cache_read_tokens: options.cache_read_tokens ?? 0,
 412→    cache_creation_tokens: options.cache_creation_tokens ?? 0,
 413→    cost_usd: options.cost_usd,
 414→    latency_ms: options.latency_ms,
 415→    stop_reason: options.stop_reason ?? "end_turn",
 416→    workspace: workspaceRecord,
 417→    actor: actorRecord,
 418→    created_at: options.created_at ?? new Date(),
 419→  };
 420→
 421→  // Link session directly on trace record (schema: session TYPE option<record<agent_session>>)
 422→  if (options.sessionId) {
 423→    traceContent.session = new RecordId("agent_session", options.sessionId);
 424→  }
 425→
 426→  await surreal.query(`CREATE $trace CONTENT $content;`, {
 427→    trace: traceRecord,
 428→    content: traceContent,
 429→  });
 430→
 431→  // Create workspace edge
 432→  await surreal.query(
 433→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
 434→    { trace: traceRecord, workspace: workspaceRecord },
 435→  );
 436→
 437→  // Create task edge if provided
 438→  if (options.taskId) {
 439→    const taskRecord = new RecordId("task", options.taskId);
 440→    await surreal.query(
 441→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
 442→      { trace: traceRecord, task: taskRecord },
 443→    );
 444→  }
 445→
 446→  // Create session edge if provided
 447→  if (options.sessionId) {
 448→    const sessionRecord = new RecordId("agent_session", options.sessionId);
 449→    await surreal.query(
 450→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
 451→      { trace: traceRecord, sess: sessionRecord },
 452→    );
 453→  }
 454→
 455→  return traceId;
 456→}
